using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Map "Yes"/"No" string to boolean for the Label column
var data = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var rowCount = (int)data.GetColumn<float>("Age").LongCount();

IDataView trainData, testData;
if (rowCount >= 10)
{
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
    trainData = split.TrainSet;
    testData = split.TestSet;
}
else
{
    // Dataset too small for a meaningful split — train and evaluate on all data
    trainData = data;
    testData = data;
}

var pipeline = mlContext.Transforms.CustomMapping<CustomerData, ChurnLabel>(
        (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(trainData);

var predictions = model.Transform(testData);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
mlContext.Model.Save(model, trainData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var customerData = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };

    var prediction = pool.Predict(customerData);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Confidence = prediction.Probability
    });
});

app.Run();

// --- Models ---

