if (rowCount >= 10)
{
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
    trainData = split.TrainSet;
    testData = split.TestSet;
}
else
{
    // Dataset too small for a meaningful split — train and evaluate on all data
    trainData = data;
    testData = data;
}

var labelLookup = mlContext.Data.LoadFromEnumerable(new[]
{
    new LabelMapping { Churned = "Yes", Label = true },
    new LabelMapping { Churned = "No",  Label = false }
});

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", labelLookup, labelLookup.Schema["Churned"], labelLookup.Schema["Label"], nameof(CustomerData.Churned))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(trainData);

var predictions = model.Transform(testData);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Use the in-memory model directly with PredictionEngine
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

var app = builder.Build();

app.MapPost("/predict", (CustomerInput input) =>
{
    var customerData = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(customerData);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Confidence = prediction.Probability
    });
});

app.Run();

